noncompliant:
void badNestedIf(bool a, bool b) {
    // Noncompliant: dangling else - unclear which if it belongs to
    if (a)
        if (b)
            doSomething();
        else // Is this for if(a) or if(b)? (Actually for if(b))
            doSomethingElse();
}

void anotherBadExample(int x, int y) {
    // Noncompliant: misleading indentation
    if (x > 0)
        if (y > 0)
            process();
    else // Belongs to if(y > 0), not if(x > 0)!
        handleNegative();
}

void confusingNesting(bool flag1, bool flag2, bool flag3) {
    // Noncompliant: multiple levels of nesting without braces
    if (flag1)
        if (flag2)
            if (flag3)
                action1();
            else
                action2();
        else
            action3();
}

compliant:
void goodNestedIf(bool a, bool b) {
    // Compliant: clear matching with braces
    if (a) {
        if (b) {
            doSomething();
        } else {
            doSomethingElse();
        }
    }
}

void betterExample(int x, int y) {
    // Compliant: explicit braces make intent clear
    if (x > 0) {
        if (y > 0) {
            process();
        } else {
            handleNegative();
        }
    }
}

void clearNesting(bool flag1, bool flag2, bool flag3) {
    // Compliant: proper bracing eliminates ambiguity
    if (flag1) {
        if (flag2) {
            if (flag3) {
                action1();
            } else {
                action2();
            }
        } else {
            action3();
        }
    }
}

void alternativeApproach(bool a, bool b) {
    // Compliant: separate if statements when appropriate
    if (!a) return;

    if (b) {
        doSomething();
    } else {
        doSomethingElse();
    }
}
